function BadgeIcon({ icon, color, size = 13 }: { icon: string | null; color: string; size?: number }) {
  if (!icon) return <Trophy size={size} style={{ color }} />;
  const LucideIcon = ICON_MAP[icon.trim().toLowerCase()] || ICON_MAP[icon.trim()];
  if (LucideIcon) return <LucideIcon size={size} style={{ color }} />;
  return <span style={{ fontSize: size, lineHeight: 1 }}>{icon}</span>;
}

