function getHueRotation(hexColor: string): number {
  const hex = hexColor.replace("#", "");
  const r = parseInt(hex.substr(0, 2), 16) / 255;
  const g = parseInt(hex.substr(2, 2), 16) / 255;
  const b = parseInt(hex.substr(4, 2), 16) / 255;
  const max = Math.max(r, g, b), min = Math.min(r, g, b);
  let h = 0;
  if (max !== min) {
    const d = max - min;
    switch (max) {
      case r: h = ((g - b) / d + (g < b ? 6 : 0)) / 6; break;
      case g: h = ((b - r) / d + 2) / 6; break;
      case b: h = ((r - g) / d + 4) / 6; break;
    }
  }
  return Math.round(h * 360);
}

function PlatformIcon({ platform, size = 24, customization }: {
  platform: string; size?: number; customization?: CustomizationData | null;
}) {
  const meta = platformSlugs[platform];
  const monochrome = customization?.monochrome_icons || false;
  const iconColor = customization?.icon_color || "#ffffff";
  const monoFilter = iconColor !== "#ffffff"
    ? `brightness(0) saturate(100%) hue-rotate(${getHueRotation(iconColor)}deg) brightness(1.5)`
    : "brightness(0) saturate(100%) invert(1)";

  if (!meta || meta.slug === "custom") {
    return (
      <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke={iconColor} strokeWidth="2">
        <circle cx="12" cy="12" r="10" /><line x1="2" y1="12" x2="22" y2="12" />
        <path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z" />
      </svg>
    );
  }
  return (
    <img
      src={`https://cdn.simpleicons.org/${meta.slug}/${meta.hex}`}
      alt={platform} width={size} height={size}
      style={{ display: "block", flexShrink: 0, filter: monochrome ? monoFilter : undefined }}
      onError={(e) => {
        const img = e.target as HTMLImageElement;
        img.src = `https://unpkg.com/simple-icons@latest/icons/${meta.slug}.svg`;
        img.style.filter = monochrome ? monoFilter : "brightness(0) saturate(100%) invert(1)";
        img.onerror = () => { img.style.display = "none"; };
      }}
    />
  );
}

/* ─────────────────────────────────────────────
   CSS INJECTION HELPER
───────────────────────────────────────────── */
function injectCSS(id: string, css: string) {
  if (typeof document !== "undefined" && !document.getElementById(id)) {
    const s = document.createElement("style");
    s.id = id;
    s.textContent = css;
    document.head.appendChild(s);
  }
}

